import { describe, expect, mock, test } from '@a0n/gnosis/test';

describe('Gnosis test expect', () => {
  test('supports partial object matching and mock call assertions', () => {
    const handler = mock((value: string) => ({ value, ok: true }));

    expect(handler).not.toHaveBeenCalled();
    expect(handler('gnosis')).toMatchObject({
      ok: true,
      value: 'gnosis',
    });
    expect(handler).toHaveBeenCalled();
    expect(handler).toHaveBeenCalledTimes(1);
  });

  test('supports rejects.toThrow', async () => {
    await expect(
      Promise.reject(new Error('deterministic failure'))
    ).rejects.toThrow('deterministic failure');
  });
});
